import{c as t,Q as a,j as i,m as l}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"I deleted 224 of 247 Claude Skills I tested. Here are the 23 I kept.","description":"","frontmatter":{"title":"I deleted 224 of 247 Claude Skills I tested. Here are the 23 I kept.","author":"@Mnilax (Mnimiy)","date":"2026-05-05T00:00:00.000Z","source":"https://x.com/Mnilax/status/2051701429987897712","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-05-@Mnilax-897712.md","filePath":"research/tweets/2026-05-05-@Mnilax-897712.md","lastUpdated":1779898012000}'),s={name:"research/tweets/2026-05-05-@Mnilax-897712.md"};function o(r,e,n,d,h,c){return a(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="i-deleted-224-of-247-claude-skills-i-tested-here-are-the-23-i-kept" tabindex="-1">I deleted 224 of 247 Claude Skills I tested. Here are the 23 I kept. <a class="header-anchor" href="#i-deleted-224-of-247-claude-skills-i-tested-here-are-the-23-i-kept" aria-label="Permalink to &quot;I deleted 224 of 247 Claude Skills I tested. Here are the 23 I kept.&quot;">​</a></h1><ul><li><strong>作者</strong>：@Mnilax (Mnimiy)</li><li><strong>來源</strong>：<a href="https://x.com/Mnilax/status/2051701429987897712" target="_blank" rel="noreferrer">https://x.com/Mnilax/status/2051701429987897712</a></li><li><strong>發布日期</strong>：2026-05-05</li><li><strong>歸檔日期</strong>：2026-05-15</li><li><strong>統計</strong>：👍 969 · 🔖 3,072 · 👁 239,572</li></ul><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>247 個 Skills 測試 6 週，保留 23 個（9.3% pass rate）；Tier S 5 個必裝；5-7 active skills 上限；Capability vs Discipline 雙框架是品質差距的核心。</p><hr><h2 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h2><ol><li><strong>嚴格量化評估方法</strong>：每個 skill 在乾淨環境跑 5 個代表性任務，雙門檻（1.5分品質提升 + 30% 時間節省），其中一個不過就刪</li><li><strong>失敗模式四分類</strong>：~80個「Cursor-style prompt collections」（只是 markdown，model 自己就能做）、~50個功能重複（多 code reviewer 相互衝突）、~40個 hooks spec 過期（v2.1 新增 21 個事件但未更新）、~25個惡意/被入侵（2026/1 ECC AgentShield 掃出 12% compromised）</li><li><strong>安裝順序 &gt; 安裝清單</strong>：一次裝 23 個 = context window 爆炸；Week 1 裝 4 個基礎（skill-creator/simplify/superpowers/frontend-design），再按缺口補；5-7 個活躍上限</li><li><strong>Capability vs Discipline 框架</strong>：Capability skills（Claude 沒有就無法完成）vs Discipline skills（Claude 能做但不是你的風格）；大多數品質改善來自 Discipline，而大多數人只裝 Capability</li><li><strong>context overhead 量化</strong>：9+ 個活躍 skills 在「on load when in doubt」模式下，每次任務有 ~13,500 tokens skill overhead，超過 CLAUDE.md 本身的 baseline tax</li></ol><hr><h2 id="關鍵數據-工具-引用" tabindex="-1">關鍵數據 / 工具 / 引用 <a class="header-anchor" href="#關鍵數據-工具-引用" aria-label="Permalink to &quot;關鍵數據 / 工具 / 引用&quot;">​</a></h2><ul><li>247 tested → 23 kept（9.3% pass rate），6 週測試</li><li>惡意 skills：2,857 個掃描中 341 個惡意（12%），2026 年 1 月單月（ECC AgentShield）</li><li>9+ active skills → ~13,500 tokens overhead per task</li><li>900,000+ community skills（2026年5月），2025年10月時只有 16 個官方 skills</li><li>superpowers: 177K+ stars（2026年4月底），3月初 94K → 4月底 177K，增長最快</li><li>frontend-design: 277K+ installs；simplify: ~133K weekly installs</li><li>impeccable (pbakaus): Chrome overlay 直接在頁面高亮 anti-pattern</li></ul><hr><h2 id="tier-s-必裝-5-個" tabindex="-1">Tier S（必裝 5 個） <a class="header-anchor" href="#tier-s-必裝-5-個" aria-label="Permalink to &quot;Tier S（必裝 5 個）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Skill</th><th>作者</th><th>核心價值</th></tr></thead><tbody><tr><td>1</td><td>frontend-design</td><td>Anthropic</td><td>強制 aesthetic 方向，消除 AI-slop 外觀（Inter+紫色漸層）；視覺以外最大增益是 Claude 停止猶豫設計決策</td></tr><tr><td>2</td><td>superpowers</td><td>obra</td><td>7 phase workflow（brainstorm→spec→plan→TDD→subagent→review→finalize）；TDD enforcement 非建議，是強制前置條件</td></tr><tr><td>3</td><td>simplify</td><td>Anthropic</td><td>清理代碼但不改行為；核心規則「never change behavior, only expression」防止 AI 靜默改語義</td></tr><tr><td>4</td><td>skill-creator</td><td>Anthropic</td><td>走過 SKILL.md 建構流程，5 分鐘建一個 skill（無此 skill 前需 1 下午）；Claude Code v2.1+ 預設啟用</td></tr><tr><td>5</td><td>web-design-guidelines</td><td>vercel-labs</td><td>100+ 規則審計 UI code，包括 ESLint a11y 插件抓不到的 focus state 違規</td></tr></tbody></table><hr><h2 id="tier-a-領域必裝-8-個" tabindex="-1">Tier A（領域必裝 8 個） <a class="header-anchor" href="#tier-a-領域必裝-8-個" aria-label="Permalink to &quot;Tier A（領域必裝 8 個）&quot;">​</a></h2><p>ui-ux-pro-max（50+ UI styles, 97 color palettes）、composition-patterns（compound components, 反 boolean props）、valyu（36+ 專業資料源，SEC/PubMed/FRED；FreshQA 79% vs Google 39%）、claude-seo（DataForSEO 實時數據, GEO-first）、agent-browser（Playwright MCP 替代品）、excalidraw-diagram、notebooklm-integration、remotion-best-practices</p><hr><h2 id="tier-b-觸發條件符合才裝-10-個" tabindex="-1">Tier B（觸發條件符合才裝 10 個） <a class="header-anchor" href="#tier-b-觸發條件符合才裝-10-個" aria-label="Permalink to &quot;Tier B（觸發條件符合才裝 10 個）&quot;">​</a></h2><p>pdf / docx / pptx / xlsx（Anthropic 文件類）、marketing-skills、mattpocock/skills（TypeScript）、claude-deep-research-skill、firecrawl、obsidian-skills（kepano）、awesome-claude-skills（meta-catalog）</p><hr><h2 id="安裝順序-比清單更重要" tabindex="-1">安裝順序（比清單更重要） <a class="header-anchor" href="#安裝順序-比清單更重要" aria-label="Permalink to &quot;安裝順序（比清單更重要）&quot;">​</a></h2><p><strong>Week 1</strong>（4 個基礎）：skill-creator → simplify → superpowers → frontend-design（或對應 backend skill）</p><p><strong>Week 2</strong>（按缺口 1-2 個）：UI → web-design-guidelines+ui-ux-pro-max；TypeScript → mattpocock；研究/數據 → valyu</p><p><strong>Week 3+</strong>（領域 1-2 個）：按需補文件/圖表/影片類</p><p><strong>上限：5-7 個活躍 skills</strong>。超過 = context overhead &gt; 回報。</p><p>每兩週稽核：30天未 fire → 停用；出現缺口 → 補一個</p><hr><h2 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h2><ol><li><strong>測試覆蓋面有限</strong>：247 個 skills = 市場的 0.028%（900K+ community），測試基準是主觀的 1-5 分量表，外部可重複性有限；但方法論的設計本身（雙門檻、5 task baseline）比大多數「試用了 X 個」文章嚴謹</li><li><strong>Tier S 偏 Anthropic/大廠</strong>：5 個中有 3 個是 Anthropic 官方，選擇偏向有維護資源的 skills，可能錯過社區長尾珍珠（honorable mentions: spartan-ai-toolkit/tdd-guard/claude-mem 等被認可為「不需要但是好 skill」）</li><li><strong>惡意 12% 來自 ECC AgentShield 第三方文件</strong>，非作者第一手掃描，需對數字保留，但作者自己的「~25 malicious or compromised」第一手觀察印證了量級</li></ol><hr><h2 id="整合決策" tabindex="-1">整合決策 <a class="header-anchor" href="#整合決策" aria-label="Permalink to &quot;整合決策&quot;">​</a></h2><p><strong>Skill</strong>（7.95/10）：Skills 稽核方法論 + install order 策略可封裝為可重複執行的 skill</p><hr><h2 id="_5-維度評分" tabindex="-1">5 維度評分 <a class="header-anchor" href="#_5-維度評分" aria-label="Permalink to &quot;5 維度評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>9</td><td>具體清單、安裝順序、weekly audit ritual、5-7上限直接可用</td></tr><tr><td>B. 創新性 (20%)</td><td>7</td><td>Capability vs Discipline 框架有力；量化評估標準在 skills review 文章中少見</td></tr><tr><td>C. 證據品質 (20%)</td><td>8</td><td>6週×247個×5任務，有量化通過標準，惡意數據有標注來源</td></tr><tr><td>D. 技術深度 (15%)</td><td>7</td><td>context overhead 量化、hooks spec 版本影響分析；缺 SKILL.md schema 底層細節</td></tr><tr><td>E. 泛化性 (15%)</td><td>8</td><td>適用所有 Claude Code 用戶；Capability/Discipline 框架可推廣到任何工具選擇</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.95</strong></td><td></td></tr></tbody></table><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>The Claude Skills marketplace went from 16 official skills in October 2025 to 900,000+ community skills by May 2026. Most of them are noise. A handful changed how I work permanently. The rest broke my context window, conflicted with each other, or did literally nothing.</p><p>I spent 6 weeks installing skills, running each on real projects, and timing the difference.</p><p>247 in. 23 kept. Everything else uninstalled.</p><p>Each skill: what it does, what surprised me, when to install it, when to skip it.</p><p>Plus the install order, because if you install all 23 at once, you&#39;ll burn through your context window before Claude generates a single useful token.</p><h2 id="the-methodology-so-you-can-trust-the-ranking" tabindex="-1">The methodology (so you can trust the ranking) <a class="header-anchor" href="#the-methodology-so-you-can-trust-the-ranking" aria-label="Permalink to &quot;The methodology (so you can trust the ranking)&quot;">​</a></h2><p>I didn&#39;t trust install counts. Half of the high-install skills I tested produced nothing measurable. Here&#39;s what I actually did:</p><h3 id="for-each-skill" tabindex="-1">For each skill: <a class="header-anchor" href="#for-each-skill" aria-label="Permalink to &quot;For each skill:&quot;">​</a></h3><ol><li>Installed in isolation on a fresh ~/.claude/ directory</li><li>Ran 5 representative tasks the skill claims to handle</li><li>Timed each run against a baseline (no skill)</li><li>Counted output quality manually on a 1-5 scale</li><li>Tracked context overhead (tokens injected per session)</li></ol><p>Pass criteria:</p><ul><li>Quality improvement of at least 1.5 points on the 5-scale</li><li>Time savings of at least 30% on its core task</li><li>Made possible something the baseline genuinely could not do</li></ul><p>Fail criteria:</p><ul><li>No measurable improvement</li><li>Adds more context than it returns in value</li><li>Conflicts with another already-installed skill (cascade detected via the lock-file diagnostic)</li><li>Hasn&#39;t been updated since February 2026</li></ul><p>That&#39;s how 247 became 23.</p><h2 id="tier-s-install-on-every-machine-every-project-5-skills" tabindex="-1">Tier S: install on every machine, every project (5 skills) <a class="header-anchor" href="#tier-s-install-on-every-machine-every-project-5-skills" aria-label="Permalink to &quot;Tier S: install on every machine, every project (5 skills)&quot;">​</a></h2><p>These five gave the largest measurable lift. If you install nothing else from this article, install these.</p><h3 id="_1-frontend-design-anthropic-277k-installs-66k-repo-stars" tabindex="-1">1. frontend-design (Anthropic, 277K+ installs, ~66K repo stars) <a class="header-anchor" href="#_1-frontend-design-anthropic-277k-installs-66k-repo-stars" aria-label="Permalink to &quot;1. frontend-design (Anthropic, 277K+ installs, ~66K repo stars)&quot;">​</a></h3><p>What it does: forces Claude into a real design direction — brutalist, editorial, retro-futurist, whatever, before writing any code. Eliminates the AI-slop look (Inter font, purple gradient on white, grid cards) that signals &quot;this was generated.&quot;</p><p>Install: /plugin marketplace add anthropics/skills &amp;&amp; /plugin install frontend-design</p><p>Surprise: the biggest gain wasn&#39;t visual. It was that Claude stopped second-guessing aesthetic decisions. Once a direction is committed, every subsequent component matches.</p><p>When to install: any project with a UI surface. Even internal tools.</p><p>When to skip: pure backend / API work.</p><p>Worth knowing: pbakaus/impeccable is now a serious alternative, it&#39;s 23 commands instead of one auto-trigger, two distinct modes (brand vs product), and a Chrome overlay that highlights anti-patterns directly on the page. Install one or the other, not both. They fight on the same task.</p><h3 id="_2-superpowers-obra-177k-stars" tabindex="-1">2. superpowers (obra, 177K+ stars) <a class="header-anchor" href="#_2-superpowers-obra-177k-stars" aria-label="Permalink to &quot;2. superpowers (obra, 177K+ stars)&quot;">​</a></h3><p>What it does: replaces ad-hoc prompting with a 7-phase workflow — brainstorm -&gt; spec -&gt; plan -&gt; TDD -&gt; subagent execution -&gt; review -&gt; finalize.</p><p>The TDD enforcement isn&#39;t a suggestion: the skill literally refuses to write implementation before a failing test exists.</p><p>Install: /plugin marketplace add obra/superpowers-marketplace &amp;&amp; /plugin install superpowers</p><p>Or, since January 15, 2026, directly from the official Anthropic marketplace: /plugin install superpowers@claude-plugins-official</p><p>Surprise: I expected this to slow me down. It didn&#39;t. The 20 minutes of upfront brainstorming saved 3 hours of unwinding wrong directions. Simon Willison called the underlying ideas &quot;genuinely fascinating&quot; — and the repo went from 94K stars in early March to 177K by end of April. Fastest growing Claude Code project of 2026 by a margin.</p><p>When to install: any feature that takes more than one session to build.</p><p>When to skip: small fixes, exploratory prototyping, single-file scripts.</p><h3 id="_3-simplify-anthropic-133k-weekly-installs" tabindex="-1">3. simplify (Anthropic, ~133K weekly installs) <a class="header-anchor" href="#_3-simplify-anthropic-133k-weekly-installs" aria-label="Permalink to &quot;3. simplify (Anthropic, ~133K weekly installs)&quot;">​</a></h3><p>What it does: takes recently-modified code and cleans it without changing behavior. Specifically targets nested ternaries, three-jobs-in-one functions, abstractions that &quot;made sense at the time.&quot;</p><p>Install: /plugin marketplace add anthropics/claude-plugins-official &amp;&amp; /plugin install code-simplifier@claude-plugins-official</p><p>Surprise: the rule it enforces — &quot;never change behavior, only how behavior is expressed&quot; — kept me from accidentally refactoring my logic. Most &quot;AI cleanups&quot; silently change semantics. This one doesn&#39;t.</p><p>When to install: every project. Run after every coding session.</p><p>When to skip: never.</p><h3 id="_4-skill-creator-anthropic" tabindex="-1">4. skill-creator (Anthropic) <a class="header-anchor" href="#_4-skill-creator-anthropic" aria-label="Permalink to &quot;4. skill-creator (Anthropic)&quot;">​</a></h3><p>What it does: walks you through building your own skills properly — describes the workflow, proposes a SKILL.md, runs 3-5 test prompts, refines instructions based on failures. Meta-skill that makes every other skill better.</p><p>Install: enabled by default in Claude Code v2.1+. If disabled: /plugin install skill-creator@anthropics/claude-code.</p><p>Surprise: writing your own skill took ~5 minutes once I had this. Without it, I burned an afternoon on my first attempt. The hidden value: most &quot;this skill should exist but doesn&#39;t&quot; gaps in your workflow are 10-minute fixes once you know how to scaffold a SKILL.md properly.</p><p>When to install: as soon as you find yourself writing the same CLAUDE.md instruction twice.</p><p>When to skip: only if you&#39;re genuinely a Claude consumer, never a producer.</p><h3 id="_5-web-design-guidelines-vercel-labs-agent-skills-19-5k-stars" tabindex="-1">5. web-design-guidelines (vercel-labs/agent-skills, 19.5K stars) <a class="header-anchor" href="#_5-web-design-guidelines-vercel-labs-agent-skills-19-5k-stars" aria-label="Permalink to &quot;5. web-design-guidelines (vercel-labs/agent-skills, 19.5K stars)&quot;">​</a></h3><p>What it does: 100+ rules covering accessibility, performance, UX. Reviews UI code against the latest Vercel guidelines and outputs violations in file:line format.</p><p>Install: /plugin marketplace add vercel-labs/agent-skills &amp;&amp; /plugin install web-design-guidelines</p><p>Surprise: caught an accessibility violation (visible focus state) that ESLint&#39;s a11y plugin missed entirely. Turns out &quot;technically valid HTML&quot; and &quot;actually usable&quot; are different bars.</p><p>When to install: pair with frontend-design, that one creates, this one audits.</p><p>When to skip: not building UIs.</p><h2 id="tier-a-install-if-your-work-matches-the-niche-8-skills" tabindex="-1">Tier A: install if your work matches the niche (8 skills) <a class="header-anchor" href="#tier-a-install-if-your-work-matches-the-niche-8-skills" aria-label="Permalink to &quot;Tier A: install if your work matches the niche (8 skills)&quot;">​</a></h2><p>Strong, focused. Install if your daily work touches the niche. Skip if not.</p><h3 id="_6-ui-ux-pro-max-nextlevelbuilder-29-6k-stars" tabindex="-1">6. ui-ux-pro-max (nextlevelbuilder, 29.6K stars) <a class="header-anchor" href="#_6-ui-ux-pro-max-nextlevelbuilder-29-6k-stars" aria-label="Permalink to &quot;6. ui-ux-pro-max (nextlevelbuilder, 29.6K stars)&quot;">​</a></h3><p>50+ UI styles, 97 color palettes, 57 font pairings, 99 UX guidelines, 25 chart types, 9 stacks. Ships with a Python CLI to query the design database. Install when starting from a blank Figma.</p><p>Skip when the design system already exists.</p><h3 id="_7-composition-patterns-vercel-labs" tabindex="-1">7. composition-patterns (vercel-labs) <a class="header-anchor" href="#_7-composition-patterns-vercel-labs" aria-label="Permalink to &quot;7. composition-patterns (vercel-labs)&quot;">​</a></h3><p>Teaches Claude compound components, context providers, explicit variants. The single rule that justifies install: architecture-avoid-boolean-props. If you&#39;ve inherited a component with 15 boolean props, install this. If you write modern React from scratch, optional.</p><h3 id="_8-valyu-valyuai-skills" tabindex="-1">8. valyu (valyuAI/skills) <a class="header-anchor" href="#_8-valyu-valyuai-skills" aria-label="Permalink to &quot;8. valyu (valyuAI/skills)&quot;">​</a></h3><p>Connects Claude to web search + 36+ specialized data sources: SEC filings, PubMed, ChEMBL, ClinicalTrials.gov, FRED economic indicators, academic publishers.</p><p>79% on FreshQA benchmark vs Google&#39;s 39%.</p><p>On finance-specific questions: 73% vs Google&#39;s 55%. Install if your work touches any of those domains.</p><h3 id="_9-claude-seo-agricidaniel-claude-seo" tabindex="-1">9. claude-seo (AgriciDaniel/claude-seo) <a class="header-anchor" href="#_9-claude-seo-agricidaniel-claude-seo" aria-label="Permalink to &quot;9. claude-seo (AgriciDaniel/claude-seo)&quot;">​</a></h3><p>Full-stack SEO audits with live DataForSEO data, schema validation, GEO-first optimization (citability scoring for AI crawlers).</p><p>12 sub-skills. Install if SEO is part of your job.</p><h3 id="_10-agent-browser" tabindex="-1">10. agent-browser <a class="header-anchor" href="#_10-agent-browser" aria-label="Permalink to &quot;10. agent-browser&quot;">​</a></h3><p>Lets Claude control any web interface through stable element refs — no clean API required.</p><p>Clicks, fills, screenshots, parallel sessions. The Playwright MCP alternative for when Playwright is overkill.</p><h3 id="_11-excalidraw-diagram" tabindex="-1">11. excalidraw-diagram <a class="header-anchor" href="#_11-excalidraw-diagram" aria-label="Permalink to &quot;11. excalidraw-diagram&quot;">​</a></h3><p>Generates Excalidraw-style diagrams from natural language. Install if architecture diagrams are part of your communication.</p><p>Skip if you live in code only.</p><h3 id="_12-notebooklm-integration" tabindex="-1">12. notebooklm-integration <a class="header-anchor" href="#_12-notebooklm-integration" aria-label="Permalink to &quot;12. notebooklm-integration&quot;">​</a></h3><p>Bridges Claude with NotebookLM. Upload specs / API references / research papers once, query them from Claude with citations.</p><p>Install for documentation-heavy projects.</p><h3 id="_13-remotion-best-practices-remotion-dev-skills-117k-weekly-installs" tabindex="-1">13. remotion-best-practices (remotion-dev/skills, 117K weekly installs) <a class="header-anchor" href="#_13-remotion-best-practices-remotion-dev-skills-117k-weekly-installs" aria-label="Permalink to &quot;13. remotion-best-practices (remotion-dev/skills, 117K weekly installs)&quot;">​</a></h3><p>Programmatic video generation in React. Install if you need product demos / release videos / explainers without a separate video workflow.</p><p>Skip if you don&#39;t.</p><h2 id="tier-b-useful-but-specific-10-skills" tabindex="-1">Tier B: useful but specific (10 skills) <a class="header-anchor" href="#tier-b-useful-but-specific-10-skills" aria-label="Permalink to &quot;Tier B: useful but specific (10 skills)&quot;">​</a></h2><p>Worth installing if the trigger condition matches.</p><ol start="14"><li>pdf (Anthropic) - forms, invoices, table extraction</li><li>docx (Anthropic) - word doc generation/editing with tracked changes</li><li>pptx (Anthropic) - slide decks from natural language</li><li>xlsx (Anthropic) - spreadsheet generation, formulas, charts</li><li>marketing-skills (coreyhaines) - CRO, copywriting, email sequences, growth</li><li>mattpocock/skills - TypeScript daily, type safety, migrations</li><li>claude-deep-research-skill - 8-phase research with auto-continuation</li><li>firecrawl - scraping hostile/JS-heavy sites</li><li>obsidian-skills (kepano, by Obsidian&#39;s CEO) - auto-tagging, auto-linking, vault-native</li><li>awesome-claude-skills (travisvn) - meta-catalog 22k stars, browse before building</li></ol><h2 id="the-224-i-deleted-and-why" tabindex="-1">The 224 I deleted (and why) <a class="header-anchor" href="#the-224-i-deleted-and-why" aria-label="Permalink to &quot;The 224 I deleted (and why)&quot;">​</a></h2><p>~80 skills were &quot;Cursor-style&quot; prompt collections. A markdown file with 50 generic rules. No SKILL.md schema. Installs as documentation. Provides nothing the model couldn&#39;t already do with CLAUDE.md.</p><p>~50 skills duplicated functionality of better-maintained skills. Two TDD frameworks. Three security scanners. Five &quot;code reviewers.&quot; When I instrumented hooks, they fired in series and produced contradictory output. Pick one per category.</p><p>~40 skills had no commits since February 2026. Claude Code&#39;s hook spec changed in v2.1 (added 21 lifecycle events), and these skills broke silently. The PostToolUseFailure event in particular invalidates a lot of older &quot;auto-fix&quot; skills that assumed the old failure model.</p><p>~25 skills were straight-up malicious or compromised. Pattern: high stars (500+), repo created after February 2026, no contributor history, dependency on a sketchy package. ECC&#39;s AgentShield documented 341 malicious skills out of 2,857 scanned on one major marketplace in January 2026 alone — 12% compromised, in a single month.</p><p>Treat new high-star skills like new high-yield wallets — too clean usually means farmed or worse.</p><p>~20 skills did basically nothing. They installed cleanly, didn&#39;t conflict, didn&#39;t break — but didn&#39;t measurably improve anything. Net effect zero, with a small context tax.</p><p>~9 skills were excellent but redundant with one of the 23 above. Honorable mentions: spartan-ai-toolkit, artifacts-builder, tdd-guard, Plannotator, claude-mem. If you&#39;re already on the 23 list, these don&#39;t add. If you want a substitute, fine.</p><h2 id="the-install-order-this-matters-more-than-the-list" tabindex="-1">The install order (this matters more than the list) <a class="header-anchor" href="#the-install-order-this-matters-more-than-the-list" aria-label="Permalink to &quot;The install order (this matters more than the list)&quot;">​</a></h2><p>Installing all 23 at once will destroy you. Each skill adds context overhead. 23 active skills will hit Claude&#39;s context window before you finish typing your first prompt. Worse, they conflict (web-design-guidelines and ui-ux-pro-max will fight on the same task).</p><p>The install order I tested:</p><p><strong>Week 1 — Foundation (4 skills, install all):</strong></p><ol><li>skill-creator (so you can build your own when gaps appear) already enabled by default in Claude Code v2.1+</li><li>simplify / code-simplifier (cleans every output)</li><li>superpowers (the workflow harness)</li><li>Pick ONE of frontend-design or backend equivalent based on your domain</li></ol><p><strong>Week 2 — Add based on the gap (1-2 more):</strong></p><ul><li>If UI work -&gt; web-design-guidelines + maybe ui-ux-pro-max</li><li>If TypeScript work -&gt; mattpocock/skills</li><li>If research / data work -&gt; valyu</li><li>If SEO / content -&gt; claude-seo</li></ul><p><strong>Week 3+ — Domain-specific (1-2 more):</strong></p><ul><li>Document-heavy -&gt; pdf, docx, pptx, xlsx (one of, rarely all four)</li><li>Diagrams -&gt; excalidraw-diagram</li><li>Video -&gt; remotion-best-practices</li></ul><p>Stop at 5-7 active skills. That&#39;s the sweet spot. Beyond that, context overhead exceeds value. Disable inactive skills with /plugin disable <code>&lt;name&gt;</code>.</p><p>There&#39;s a deeper reason for this cap. Each skill loads its SKILL.md into context whenever Claude detects relevance. With 9+ active skills running on conservative &quot;load when in doubt&quot; detection, you&#39;re paying ~13,500 tokens of skill overhead per task that needs none of them, before Claude reads your actual prompt. The same logic that caps your CLAUDE.md to 1,200 words caps your active skills to 5-7. Both are baseline tax. Both compound.</p><p>If you want a moving target: every two weeks, run an audit. Which skills did Claude actually invoke? The ones that didn&#39;t fire — disable. The gap that opened, install one new skill to fill it.</p><h2 id="what-didn-t-work" tabindex="-1">What didn&#39;t work <a class="header-anchor" href="#what-didn-t-work" aria-label="Permalink to &quot;What didn&#39;t work&quot;">​</a></h2><p>Installing skills via npx skills add blindly. Half didn&#39;t have proper SKILL.md frontmatter. They installed but Claude never invoked them. Always verify with /plugin list after install.</p><p>Trusting install counts as quality signals. Two of the top-30 by install count produced literally no measurable improvement.</p><p>Mass-installing from &quot;awesome-claude-skills&quot; lists. The curated lists optimize for breadth. You want depth in the skills you actually use.</p><p>Skipping the audit step. Without a baseline, you can&#39;t tell if Claude got better or worse.</p><p>Installing both web-design-guidelines and ui-ux-pro-max at the same time. Conflict — both drive the design phase. Pick creation (ui-ux-pro-max) OR audit (web-design-guidelines).</p><p>Installing both frontend-design and impeccable at the same time. Both encode aesthetic taste. Pick one.</p><p>Installing skills that haven&#39;t been updated in 2+ months. Hook spec changed. Skills not updated for PostToolUseFailure produce silent failures.</p><p>Using Search and Tools feature alongside skills like valyu. Both invoke web search. Disable Anthropic&#39;s built-in Search when using a search-specialist skill.</p><h3 id="how-to-maintain-your-stack" tabindex="-1">How to maintain your stack <a class="header-anchor" href="#how-to-maintain-your-stack" aria-label="Permalink to &quot;How to maintain your stack&quot;">​</a></h3><p>The marketplace ships ~50-100 new skills per week. Your stack will go stale.</p><p>A 10-minute weekly ritual: check which skills fired → disable ones that didn&#39;t → if a skill hasn&#39;t fired in 30 days, uninstall.</p><h2 id="the-mental-model" tabindex="-1">The mental model <a class="header-anchor" href="#the-mental-model" aria-label="Permalink to &quot;The mental model&quot;">​</a></h2><p>Two types of skills:</p><p><strong>Capability skills</strong> — give Claude new abilities it didn&#39;t have. firecrawl, valyu, pdf, agent-browser. Without these, Claude literally can&#39;t do the task.</p><p><strong>Discipline skills</strong> — make Claude execute the way you want. frontend-design, simplify, superpowers, web-design-guidelines. Without these, you get generic AI output.</p><p>Most people install only capability skills and wonder why their output looks like everyone else&#39;s. Most quality improvement comes from discipline skills. That&#39;s why 4 of the Tier S 5 are discipline skills, not capability skills.</p><p>For each of the next 5 tasks you do with Claude, ask: &quot;Did the output look generic, or did it look like me?&quot; If generic, you&#39;re missing discipline skills. Install one, retry the same task, compare.</p><h2 id="t-h-e-e-n-d" tabindex="-1">T H E _ E N D <a class="header-anchor" href="#t-h-e-e-n-d" aria-label="Permalink to &quot;T H E _ E N D&quot;">​</a></h2><p>The skills marketplace is the most undervalued part of the Claude ecosystem. Most people are still using vanilla Claude Code in May 2026. They feel like the model got &quot;smarter slower&quot; than the headlines suggested. It didn&#39;t. They didn&#39;t install the skills.</p><p>23 of the right skills, installed in the right order, is more important than which Claude version you&#39;re on.</p><p>If this saved you a weekend of marketplace browsing, repost.</p><blockquote><p>If this saves you a weekend of marketplace browsing, bookmark and pass it on. Part 3 next days.</p></blockquote><p>Telegram for weekly skill audits and new releases worth knowing: <a href="https://t.me/+_ZWrQN7GuDA3ZDEy" target="_blank" rel="noreferrer">https://t.me/+_ZWrQN7GuDA3ZDEy</a></p>',160)])])}const k=t(s,[["render",o]]);export{u as __pageData,k as default};
